    "TNR1215_1_18": ["ما هي الخطوة التالية؟ 15، 21، 28، 36، 45، ؟", "أضف 6، ثم 7، ثم 8، ثم 9، ثم...", ["55", "50", "54", "60"], "الاختلافات: +6، +7، +8، +9، +10. إذن 45 + 10 = 55."],
    "TNR1215_1_19": ["ما هي الخطوة التالية؟ 1، 3، 6، 10، ؟", "هذه أرقام ثلاثية. تزيد الفروق بمقدار 1.", ["15", "12", "14", "16"], "الأعداد المثلثية: +2، +3، +4، +5. إذن 10 + 5 = 15."],
    "TNR1215_1_20": ["ما هي الخطوة التالية؟ 100، 81، 64، 49، 36، ؟", "هذه مربعات كاملة مرتبة تنازليًا.", ["25", "16", "20", "30"], "المربعات المتناقصة: 10²، 9²، 8²، 7²، 6²، 5² = 25."],
    "TNR1215_2_01": ["ما هي الخطوة التالية؟ 1, 8, 27, 64, ؟", "فكر في تكعيب الأعداد الصحيحة: 1³، 2³، 3³، …", ["125", "100", "81", "216"], "المكعبات المثالية: 1³، 2³، 3³، 4³، 5³ = 125."],
