    "TNR1215_2_11": ["ما هي الخطوة التالية؟ 3، 6، 12، 24، 48، ؟", "كل رقم مضاعف.", ["96", "72", "84", "108"], "التقدم الهندسي ×2: 48 × 2 = 96."],
