    "TNR1215_2_19": ["ما هي الخطوة التالية؟ 2، 10، 50، 250، ؟", "يتم ضرب كل حد في 5.", ["1250", "500", "1000", "1500"], "التقدم الهندسي ×5: 250 × 5 = 1250."],
    "TNR1215_2_20": ["ما هي الخطوة التالية؟ 729، 512، 343، 216، 125، ؟", "تقليل المكعبات المثالية", ["64", "100", "27", "81"], "المكعبات المتناقصة: 9³، 8³، 7³، 6³، 5³، 4³ = 64."],
    "TNR1215_3_01": ["ما هي الخطوة التالية؟ 1، 2، 4، 7، 11، ؟", "أوجد الاختلافات: فهي تزيد بمقدار 1 في كل خطوة.", ["16", "14", "15", "18"], "الاختلافات هي 1، 2، 3، 4 — زيادة بمقدار 1. الفرق التالي هو 5: 11 + 5 = 16."],
